# retrieval/in_memory_index.py — deterministic test index
from pathlib import Path
from dataclasses import dataclass

@dataclass
class Chunk:
    doc_id: str
    text: str
    embedding: list[float]  # pre-computed and committed

class InMemoryIndex:
    def __init__(self, chunks: list[Chunk]) -> None:
        self._chunks = chunks

    @classmethod
    def from_files(cls, paths: list[Path]) -> "InMemoryIndex":
        """Build index from markdown files in tests/fixtures/corpus/.
        Embeddings are pre-computed and stored in .embed.json sidecar files
        so integration tests never call the embedding API.
        """
        chunks = []
        for path in paths:
            embed_path = path.with_suffix(".embed.json")
            if not embed_path.exists():
                raise FileNotFoundError(
                    f"Missing embedding sidecar: {embed_path}. "
                    "Run: python3 scripts/precompute_test_embeddings.py"
                )
            import json
            embedding = json.loads(embed_path.read_text())
            chunks.append(Chunk(
                doc_id=path.stem,
                text=path.read_text(),
                embedding=embedding,
            ))
        return cls(chunks)

    def query(self, embedding: list[float], top_k: int = 3) -> list[Chunk]:
        """Cosine similarity retrieval — deterministic for same query embedding."""
        import math
        def cosine(a, b):
            dot = sum(x*y for x,y in zip(a,b))
            na = math.sqrt(sum(x**2 for x in a))
            nb = math.sqrt(sum(x**2 for x in b))
            return dot / (na * nb + 1e-9)
        ranked = sorted(self._chunks, key=lambda c: cosine(c.embedding, embedding), reverse=True)
        return ranked[:top_k]
